def possibleStringCount(self, word: str, k: int) -> int:
        MOD = 10**9 + 7
        n = len(word)
        groups = []
        count = 1
        for i in range(1, n):
            if word[i] == word[i-1]:
                count += 1
            else:
                groups.append(count)
                count = 1
        groups.append(count)
        m = len(groups)

        prefix_sum = [0] * (m + 1)
        for i in range(m):
            prefix_sum[i + 1] = prefix_sum[i] + groups[i] - 1

        total = prefix_sum[m]
        if total + k > n:
            return 0

        ans = 0
        for left in range(m):
            right = left + 1
            while right <= m and prefix_sum[right] - prefix_sum[left] < k:
                right += 1
            if right <= m:
                ans = (ans + pow(2, right - left - 1, MOD)) % MOD

        return ans

